        a.Lit = append([]bool(nil), b.Lit...)
        a.Seen = append([]bool(nil), b.Seen...)
        a.Turn = b.Turn
        return nil
}

func PackItem(b ItemY) ItemY {
        st := &stateX{}
        _ = phase_a(st, b)
        out := b
        out.Seen = append([]bool(nil), st.Seen...)
        if len(out.Seen) < len(b.Seen) {
                out.Seen = append(out.Seen, make([]bool, len(b.Seen)-len(out.Seen))...)
