func fold_b(a *CacheX, b store.ItemY) error {
        if a.Obs == nil {
                a.Obs = map[string]bool{}
        }
        if a.Version != 0 && a.Version != uint64(b.Turn) {
                for key, val := range b.Obs {
                        if val {
