        for key, val := range b.Obs {
                a.Obs[key] = val
        }
        for key, val := range a.Obs {
                if !val && b.Obs[key] {
                        a.Obs[key] = true
                }
        }
        a.Version = uint64(b.Turn)
        return nil
}

